"""
Agent test: run the experiment to verify data paths and get MSE values.
"""

import sys
import io
from pathlib import Path

# Add workspace to path
workspace = Path(__file__).parent.parent.parent
sys.path.insert(0, str(workspace))
sys.path.insert(0, str(workspace / "lib"))

TEST_POINTS = {
    "test_run_experiment": 1,
    "test_read_matrix_data": 1,
    "test_prediction_error_methods": 1,
}


def make_result(passed, expected, actual):
    return (passed, expected, actual)


def test_run_experiment(module):
    """Run the experiment with 50 iterations to get MSE values."""
    try:
        old_stdout = sys.stdout
        sys.stdout = captured = io.StringIO()
        module.run_experiment(50)
        sys.stdout = old_stdout
        output = captured.getvalue()
        if output.strip():
            return make_result(True, "experiment output", output[:200])
        return make_result(False, "non-empty output", "empty")
    except Exception as e:
        if sys.stdout != old_stdout:
            sys.stdout = old_stdout
        return make_result(False, "experiment runs", str(e))


def test_read_matrix_data(module):
    """Test reading the actual data files."""
    import numeric
    import tempfile
    import os

    content = "2.5,6,3\n1,2,3\n"
    with tempfile.NamedTemporaryFile(mode='w', suffix='.txt', delete=False) as f:
        f.write(content)
        fname = f.name

    try:
        mat = module.read_matrix(fname)
        if mat.shape() != (2, 3):
            return make_result(False, "(2,3)", mat.shape())
        if abs(mat[0, 0] - 2.5) > 1e-9:
            return make_result(False, 2.5, mat[0, 0])
        return make_result(True, "matrix parsed", f"shape={mat.shape()}")
    finally:
        os.unlink(fname)


def test_prediction_error_methods(module):
    """Test prediction_error returns a float MSE."""
    import numeric

    # y = 2*x, perfect fit
    weights = numeric.Matrix([[2.0]])
    model = module.LinearModel(weights)
    inputs = numeric.Matrix([[1.0], [2.0], [3.0]])
    actual = numeric.Matrix([[2.0], [4.0], [6.0]])
    err = model.prediction_error(inputs, actual)
    if abs(err) > 1e-9:
        return make_result(False, 0.0, err)

    # Imperfect: actual = [[3],[5],[7]] but predictions = [[2],[4],[6]]
    actual2 = numeric.Matrix([[3.0], [5.0], [7.0]])
    err2 = model.prediction_error(inputs, actual2)
    # diff = [-1,-1,-1], MSE = 3/3 = 1
    if abs(err2 - 1.0) > 1e-9:
        return make_result(False, 1.0, err2)

    return make_result(True, "MSE correct", f"perfect=0, imperfect={err2}")

